CREATE OR REPLACE FUNCTION loader.get_order_history_path(ordine_numero character varying)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
    -- Variabile per costruire il percorso degli ordini
    ordine_path TEXT := '';
    current_ordine varchar;
    next_ordine varchar;
BEGIN
    -- Inizializza il percorso con l'ordine iniziale
    current_ordine := ordine_numero;

    LOOP
        -- Cerca l'ordine corrente per vedere se è stato sostituito da un altro ordine
        SELECT nome_testata_ordine INTO next_ordine
        FROM loader.erp_ordini
        WHERE sost_ord = current_ordine;

        -- Controlla se l'ordine corrente è stato trovato
        IF next_ordine IS NULL THEN
            -- Se non ci sono altri ordini sostitutivi, esce dal loop
            EXIT;
        ELSE
            -- Aggiunge l'ordine corrente al percorso
            ordine_path := ordine_path || current_ordine || ' -> ';
            -- Imposta l'ordine corrente al prossimo ordine nella catena
            current_ordine := next_ordine;
        END IF;
    END LOOP;

    -- Aggiunge l'ultimo ordine al percorso
    ordine_path := ordine_path || current_ordine;

    RETURN ordine_path;
END;
$function$

CREATE OR REPLACE FUNCTION loader.get_reverse_order_history_path(ordine_recente character varying)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
    -- Variabile per costruire il percorso degli ordini
    ordine_path TEXT := ordine_recente;
    current_ordine varchar := ordine_recente;
    prev_ordine varchar;
BEGIN
    LOOP
        -- Cerca l'ordine precedente che questo ordine ha sostituito
        SELECT sost_ord INTO prev_ordine
        FROM loader.erp_ordini
        WHERE nome_testata_ordine = current_ordine;

        -- Controlla se è stato trovato un ordine precedente
        IF prev_ordine IS NULL or prev_ordine = '' THEN
            -- Se non ci sono altri ordini precedenti, esce dal loop
            EXIT;
        ELSE
            -- Prepara il percorso aggiungendo l'ordine precedente all'inizio
            ordine_path := prev_ordine || ' -> ' || ordine_path;
            -- Imposta l'ordine corrente all'ordine precedente per la prossima iterazione
            current_ordine := prev_ordine;
        END IF;
    END LOOP;

    RETURN ordine_path;
END;
$function$

CREATE OR REPLACE FUNCTION loader.ordine_prossima_scadenza(data_attivazione timestamp without time zone, durata_servizio integer, durata_rinnovo integer, tacito_rinnovo integer)
 RETURNS date
 LANGUAGE plpgsql
AS $function$
DECLARE
prossima_scadenza DATE;
BEGIN
    -- Controlla se data_attivazione è NULL o inferiore a 1001-01-01
    IF data_attivazione IS NULL OR data_attivazione < '1001-01-01'::TIMESTAMP WITHOUT TIME ZONE OR
    coalesce(durata_servizio, 0) = 0
    THEN
        RETURN NULL;
    END IF;

    -- Calcola la prossima scadenza aggiungendo la durata del servizio alla data di attivazione
    prossima_scadenza := data_attivazione + (durata_servizio || ' months')::INTERVAL;

    -- Se il tacito rinnovo è attivo, calcola la prossima scadenza tenendo conto dei rinnovi
    IF tacito_rinnovo = 1 and coalesce(durata_rinnovo, 0) > 0 THEN
        WHILE prossima_scadenza <= CURRENT_DATE LOOP
            prossima_scadenza := prossima_scadenza + (durata_rinnovo || ' months')::INTERVAL;
        END LOOP;
    END IF;

RETURN prossima_scadenza;
END;
$function$

