CREATE OR REPLACE PROCEDURE loader.update_products_product_from_gamma()
 LANGUAGE plpgsql
AS $procedure$
DECLARE
    rec_articoli record;
BEGIN
insert into products.product (code, internal_name, category_id)
select trim(cod_articolo), descrizione_ita, tgpc.category_id
    from loader.erp_anagrafica_articoli_vendita a left outer join loader.trascodifica_gamma_product_category tgpc on (a.famiglia = tgpc.famiglia or tgpc.famiglia is null)
        and (a.sotto_famiglia = tgpc.sotto_famiglia or tgpc.sotto_famiglia is null)
    where descrizione_ita is not null
    on conflict do nothing ;

for rec_articoli IN
        select code, translation_uuid, a.descrizione_ita, a.descrizione_ing
            from products.product p join loader.erp_anagrafica_articoli_vendita a on p.code = trim(a.cod_articolo)
loop

    if rec_articoli.descrizione_ita is not null then
        insert into common.translation (translation_uuid, language, short, long) values
            (rec_articoli.translation_uuid, 'it', rec_articoli.descrizione_ita, '' )
        on conflict do nothing ;
    end if;

    if rec_articoli.descrizione_ing is not null then
        insert into common.translation (translation_uuid, language, short, long) values
            (rec_articoli.translation_uuid, 'en', rec_articoli.descrizione_ing, '' )
        on conflict do nothing ;
    end if;



end loop;



END
$procedure$
